VALUES
  ('social-worker-moex-02291', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「對自己的未來沒有任何想法，也不想要探索或了解可能的選擇；對於父母或重要他人的建議也不接受， 對許多重要態度、價值觀等都還沒進行承諾，但也還沒經歷認同危機。」若是依照Marcia的認同理論而 言，這位青年可能在那一個自我認同發展階段？ 認同迷失（identity diffusion）  他主定向（identity foreclosure） 延期未定（identity moratorium）  認同達成（identity achievement）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02292', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「青少年常認為很多人會關注他們的一言一行，並且覺得自己的一切相當重要，是世界的焦點。」這樣 的感受符合何種理論的敘述？ 自我中心  鏡中自我  自我認同  自我歸因', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02293', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關性騷擾（sexual harassment）的描述，下列何者錯誤？ 是指不受歡迎的性接近、性要求或其他具有性意味的言語或肢體動作等 性騷擾往往與不平等的權力與施壓等元素有關 受害人幾乎都是女性，鮮少有男性因為性騷擾而感到困擾 對特定性別語言上的評論也可能構成性騷擾，如指稱女員工情緒差「一定是每個月的那個來了」', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02294', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '小明加入一個幫派，這個幫派幫規要求成員要保護地盤，對於外來挑釁的回應要視死如歸，該幫派成員 令當地民眾避之唯恐不及。若依據莫拉萊斯（Morales）（2002）對幫派的分類，小明參與的幫派有可能 是那一種？ 犯罪型（criminal）    衝突型（conflict） 逃避型（retreatist gangs）  神秘團體（occult groups）', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02295', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Sternberg的愛情三角理論，認為愛情包含那三個元素？ 親密、激情、承諾    生理、心理、精神  慾望、期待、承諾  探索、迷戀、孤獨', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02296', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對於近年來中年勞動者的工作模式敘述，下列何者正確？ 失業對中年勞動者而言非危險因子 中年勞工的工作流動性非常低 工作和退休的界線明確且清楚，多數人退休後並不會繼續工作 中年勞工繼續接受教育是常見且普遍的現象', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02297', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '志強是一名55歲的關廠工人，由於遭到資方惡意積欠工資又求償無門，內心氣忿難平，陸陸續續透過親 友介紹工作均未能順利，志強很希望社會工作師協助他儘快找到適當的工作。若就舒伯（Super）的生涯 發展理論觀之，志強目前是處在生涯發展的那個時期？ 建立期（establishment）  探索期（exploration） 衰退期（decline）    維持期（maintenance）', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02298', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '成功老化的關鍵，不包含下列那一個？ 避免疾病        生活積極承諾 維持高認知與身體功能   選擇居住都會區', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02299', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「卓越老年的觀點認為，人類的發展會延伸到老年期，且不會因為老化而停止。」這樣的說法屬於那個 理論對老年期的應用？ 撤退理論      連續理論  社會建構理論  社會交換理論', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02300', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會工作師鼓勵長期居住在養護照顧機構的老人參與每週一次的生命回顧團體，下列那一個敘述錯誤？ 有助於老人達到生命的統整 為了避免觸景傷情，不適合運用此方法協助已喪偶老人 可以在團體中探討死亡的議題 老人在生命晚期階段總結過去的生活是有意義的', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
